// Helper functions
export const getUKCityById = (id) => ukCities.find(c => c.id === id);
export const getUKCityByName = (name) => ukCities.find(c => c.name.toLowerCase().includes(name.toLowerCase()));
export const getUKCitiesByOrgType = (orgType) => ukCities.filter(c => c.orgType === orgType);

// Organization types present
export const ukOrgTypes = [...new Set(ukCities.map(c => c.orgType))];
